package org.eclipse.rdf4j.sail.base;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.nio.file.Path;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class SketchBasedJoinEstimatorPersistenceTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	private static Statement st(Resource s, IRI p, Value o, Resource c) {
		return VF.createStatement(s, p, o, c);
	}

	private static Statement st(Resource s, IRI p, Value o) {
		return VF.createStatement(s, p, o);
	}

	private static SketchBasedJoinEstimator.Config smallConfig() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withNominalEntries(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}

	@Test
	void persistSnapshotThenLazyLoadOnDemand(@TempDir Path tempDir) {
		Resource s = VF.createIRI("urn:s");
		IRI p = VF.createIRI("urn:p");
		Value o = VF.createIRI("urn:o");

		StubSailStore sourceStore = new StubSailStore();
		sourceStore.add(st(s, p, o));
		SketchBasedJoinEstimator writer = new SketchBasedJoinEstimator(sourceStore, smallConfig());
		writer.rebuildOnceSlow();

		Path snapshot = tempDir.resolve("join-estimator.rjes");
		writer.configurePersistence(snapshot, false);
		assertTrue(writer.persistIfDirty(), "Expected dirty snapshot write");

		SketchBasedJoinEstimator reader = new SketchBasedJoinEstimator(new StubSailStore(), smallConfig());
		reader.configurePersistence(snapshot, true);
		assertTrue(reader.isReady(), "Expected lazy load on first readiness check");

		double card = reader.cardinalitySingle(SketchBasedJoinEstimator.Component.P, p.stringValue());
		assertEquals(1.0, card, 1.0);
	}

	@Test
	void unloadAndOfflineWritesRequireRebuild() {
		Resource s = VF.createIRI("urn:s");
		IRI p = VF.createIRI("urn:p");
		Value o = VF.createIRI("urn:o");

		StubSailStore store = new StubSailStore();
		store.add(st(s, p, o));
		SketchBasedJoinEstimator est = new SketchBasedJoinEstimator(store, smallConfig());
		est.rebuildOnceSlow();
		assertTrue(est.isReady());

		est.unload();
		assertFalse(est.isReady(), "Estimator should not be ready when unloaded");

		est.addStatement(st(VF.createIRI("urn:s2"), p, o));
		assertFalse(est.isReady(), "Writes while unloaded should force rebuild before readiness");

		est.rebuildOnceSlow();
		assertTrue(est.isReady(), "Rebuild should restore readiness");
	}

	@Test
	void cardinalityJoinFallsBackWhenUnloaded() {
		Resource s = VF.createIRI("urn:s");
		IRI p1 = VF.createIRI("urn:p1");
		IRI p2 = VF.createIRI("urn:p2");
		Value o = VF.createIRI("urn:o");

		StubSailStore store = new StubSailStore();
		store.add(st(s, p1, o));
		store.add(st(s, p2, o));
		SketchBasedJoinEstimator est = new SketchBasedJoinEstimator(store, smallConfig());
		est.rebuildOnceSlow();
		est.unload();

		StatementPattern left = new StatementPattern(Var.of("s"), Var.of("p1", p1), Var.of("o", o));
		StatementPattern right = new StatementPattern(Var.of("s"), Var.of("p2", p2), Var.of("o", o));

		assertEquals(-1.0, est.cardinality(new Join(left, right)), 0.0);
	}

	@Test
	void lowMemorySupplierBlocksLazyLoad(@TempDir Path tempDir) {
		Resource s = VF.createIRI("urn:s");
		IRI p = VF.createIRI("urn:p");
		Value o = VF.createIRI("urn:o");

		StubSailStore sourceStore = new StubSailStore();
		sourceStore.add(st(s, p, o));
		SketchBasedJoinEstimator writer = new SketchBasedJoinEstimator(sourceStore, smallConfig());
		writer.rebuildOnceSlow();

		Path snapshot = tempDir.resolve("join-estimator.rjes");
		writer.configurePersistence(snapshot, false);
		assertTrue(writer.persistIfDirty());

		SketchBasedJoinEstimator reader = new SketchBasedJoinEstimator(new StubSailStore(), smallConfig());
		reader.configurePersistence(snapshot, true);
		reader.setLowMemorySupplier(() -> true);
		assertFalse(reader.isReady(), "Low-memory gate must block lazy-load");

		reader.setLowMemorySupplier(() -> false);
		assertTrue(reader.isReady(), "Readiness should recover when memory gate clears");
	}
}
